from __future__ import annotations


def resample_series(points, *, start: int, end: int, interval: int):
    points = sorted(points)
    output = []
    for ts in range(start, end + 1, interval):
        value = None
        for point_ts, point_value in points:
            if point_ts <= ts:
                value = point_value
            else:
                break
        output.append((ts, value))
    return output
